class Solution:
    def calculate(self, s: str) -> int:
        tokens = []
        current_number = 0
        for c in s:
            if c.isdigit():
                current_number = current_number * 10 + int(c)
            else:
                if c != ' ':
                    if current_number != 0:
                        tokens.append(current_number)
                        current_number = 0
                    tokens.append(c)
        if current_number != 0:
            tokens.append(current_number)

        first_pass = []
        i = 0
        while i < len(tokens):
            token = tokens[i]
            if isinstance(token, int):
                first_pass.append(token)
                i += 1
            else:
                if token in '*/':
                    op = token
                    right = tokens[i+1]
                    left = first_pass.pop()
                    if op == '*':
                        res = left * right
                    else:
                        res = left // right
                    first_pass.append(res)
                    i += 2
                else:
                    first_pass.append(token)
                    i += 1

        result = first_pass[0]
        i = 1
        while i < len(first_pass):
            op = first_pass[i]
            num = first_pass[i+1]
            if op == '+':
                result += num
            else:
                result -= num
            i += 2

        return result

